import{_ as a,c as s,o as l,a1 as i}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Compatibilidad: Skills de Claude Code | opencode-agent-skills","description":"Aprende cómo OpenCode Agent Skills es compatible con los skills y el sistema de plugins de Claude Code. Domina el mecanismo de mapeo de herramientas, la prioridad de descubrimiento de skills y reutiliza el ecosistema de skills de Claude.","frontmatter":{"title":"Compatibilidad: Skills de Claude Code | opencode-agent-skills","sidebarTitle":"Reutilizar Skills de Claude","subtitle":"Compatibilidad con Skills de Claude Code","description":"Aprende cómo OpenCode Agent Skills es compatible con los skills y el sistema de plugins de Claude Code. Domina el mecanismo de mapeo de herramientas, la prioridad de descubrimiento de skills y reutiliza el ecosistema de skills de Claude.","tags":["Compatibilidad","Claude Code","Reutilización de Skills"],"prerequisite":["start-what-is-opencode-agent-skills","platforms-skill-discovery-mechanism"],"order":1},"headers":[],"relativePath":"es/joshuadavidthomas/opencode-agent-skills/advanced/claude-code-compatibility/index.md","filePath":"es/joshuadavidthomas/opencode-agent-skills/advanced/claude-code-compatibility/index.md"}'),o={name:"es/joshuadavidthomas/opencode-agent-skills/advanced/claude-code-compatibility/index.md"};function d(t,e,n,r,c,u){return l(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="compatibilidad-con-skills-de-claude-code" tabindex="-1">Compatibilidad con Skills de Claude Code <a class="header-anchor" href="#compatibilidad-con-skills-de-claude-code" aria-label="Permalink to &quot;Compatibilidad con Skills de Claude Code&quot;">​</a></h1><h2 id="lo-que-aprenderas" tabindex="-1">Lo que aprenderás <a class="header-anchor" href="#lo-que-aprenderas" aria-label="Permalink to &quot;Lo que aprenderás&quot;">​</a></h2><ul><li>Entender cómo el plugin es automáticamente compatible con el formato de skills de Claude Code</li><li>Dominar el mecanismo de mapeo de herramientas para que los skills de Claude funcionen correctamente en OpenCode</li><li>Conocer las reglas completas de prioridad en el descubrimiento de skills</li><li>Reutilizar skills existentes del marketplace de plugins de Claude sin necesidad de reescribirlos</li></ul><h2 id="tu-situacion-actual" tabindex="-1">Tu situación actual <a class="header-anchor" href="#tu-situacion-actual" aria-label="Permalink to &quot;Tu situación actual&quot;">​</a></h2><p>Ya tienes algunos skills de Claude Code, o quieres usar skills del marketplace de plugins de Claude, pero estos skills fueron escritos para Claude Code. Usarlos directamente en OpenCode presenta problemas:</p><ul><li>Las llamadas a herramientas en los skills de Claude (como <code>TodoWrite</code>, <code>Task</code>) no existen en OpenCode</li><li>No está claro cómo hacer que OpenCode encuentre los skills de plugins de Claude instalados</li><li>Te preocupa que el formato de los skills sea incompatible y tengas que reescribir todo</li></ul><h2 id="concepto-central" tabindex="-1">Concepto central <a class="header-anchor" href="#concepto-central" aria-label="Permalink to &quot;Concepto central&quot;">​</a></h2><p>El plugin OpenCode Agent Skills utiliza un <strong>mecanismo de compatibilidad de tres capas</strong> que te permite usar skills de Claude Code sin modificaciones:</p><ol><li><strong>Descubrimiento automático</strong> - Escanea skills desde los directorios estándar de Claude Code (<code>.claude/skills/</code>, <code>~/.claude/plugins/</code>)</li><li><strong>Mapeo de herramientas</strong> - Al cargar un skill, inyecta automáticamente una guía de mapeo que convierte los nombres de herramientas de Claude a nombres de OpenCode</li><li><strong>Soporte de formatos</strong> - Compatible con los formatos de instalación v1 y v2 de plugins de Claude</li></ol><div class="info custom-block"><p class="custom-block-title">Concepto clave</p><p><strong>Formato de skills de Claude Code</strong> - Especificación de skills definida por Anthropic, que usa archivos <code>SKILL.md</code> para describir skills, incluyendo frontmatter YAML (metadatos) y contenido Markdown (instrucciones).</p></div><h3 id="principio-del-mapeo-de-herramientas" tabindex="-1">Principio del mapeo de herramientas <a class="header-anchor" href="#principio-del-mapeo-de-herramientas" aria-label="Permalink to &quot;Principio del mapeo de herramientas&quot;">​</a></h3><p>Cuando el plugin detecta que se está cargando un skill escrito para Claude Code, inyecta automáticamente una guía de mapeo de herramientas:</p><table tabindex="0"><thead><tr><th>Herramienta Claude Code</th><th>Herramienta OpenCode</th><th>Regla de mapeo</th></tr></thead><tbody><tr><td><code>TodoWrite/TodoRead</code></td><td><code>todowrite/todoread</code></td><td>Minúsculas</td></tr><tr><td><code>Task</code> (subagente)</td><td><code>task</code> (con parámetro subagent_type)</td><td>Usar parámetro</td></tr><tr><td><code>Skill</code></td><td><code>use_skill</code></td><td>Reemplazar nombre</td></tr><tr><td><code>Read/Write/Edit/Bash/Glob/Grep/WebFetch</code></td><td><code>read/write/edit/bash/glob/grep/webfetch</code></td><td>Minúsculas</td></tr></tbody></table><p><strong>Método de mapeo</strong>: El plugin inyecta la guía de mapeo como XML en el contexto de la sesión al cargar el skill, y la IA automáticamente llama a las herramientas correctas según el mapeo.</p><div class="tip custom-block"><p class="custom-block-title">¿Por qué es necesario el mapeo?</p><p>Claude Code y OpenCode tienen diferentes estilos de nomenclatura de herramientas. Claude usa PascalCase (como <code>TodoWrite</code>), mientras que OpenCode usa minúsculas (como <code>todowrite</code>). El mapeo de herramientas le indica a la IA cómo convertir las llamadas.</p></div><h3 id="prioridad-de-descubrimiento-de-skills" tabindex="-1">Prioridad de descubrimiento de skills <a class="header-anchor" href="#prioridad-de-descubrimiento-de-skills" aria-label="Permalink to &quot;Prioridad de descubrimiento de skills&quot;">​</a></h3><p>El plugin descubre skills en el siguiente orden, <strong>el primer skill que coincide tiene efecto</strong> (los skills con el mismo nombre no se duplican):</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">graph TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[Flujo de descubrimiento de skills] --&gt; B[OpenCode nivel proyecto]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; |.opencode/skills/| C[1. project]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[Claude Code nivel proyecto]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; |.claude/skills/| E[2. claude-project]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; F[OpenCode nivel usuario]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    F --&gt; |~/.config/opencode/skills/| G[3. user]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    G --&gt; H[Claude Code nivel usuario]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    H --&gt; |~/.claude/skills/| I[4. claude-user]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    I --&gt; J[Caché de plugins Claude]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    J --&gt; |~/.claude/plugins/cache/| K[5. claude-plugins]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    K --&gt; L[Marketplace de plugins Claude]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    L --&gt; |~/.claude/plugins/marketplaces/| M[6. claude-plugins]</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style C fill:#e1f5e1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style E fill:#fff4e1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style G fill:#e1f5e1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style I fill:#fff4e1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style K fill:#fff4e1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style M fill:#fff4e1</span></span></code></pre></div><p><strong>Reglas de prioridad</strong>:</p><ul><li>Los skills a nivel de proyecto sobrescriben los de nivel de usuario (conveniente para personalización del proyecto)</li><li>Los skills de OpenCode tienen prioridad sobre los de Claude (para evitar confusión)</li><li>Solo se conserva la primera versión descubierta de skills con el mismo nombre</li></ul><details class="details custom-block"><summary>Ejemplo: Sobrescritura de skills con el mismo nombre</summary><p>Supongamos que tienes un skill llamado <code>git-helper</code> en dos ubicaciones:</p><ul><li><code>.claude/skills/git-helper/SKILL.md</code> (versión Claude)</li><li><code>.opencode/skills/git-helper/SKILL.md</code> (versión OpenCode)</li></ul><p><strong>Resultado</strong>: La versión de OpenCode tiene efecto (mayor prioridad)</p></details><h2 id="🎒-antes-de-empezar" tabindex="-1">🎒 Antes de empezar <a class="header-anchor" href="#🎒-antes-de-empezar" aria-label="Permalink to &quot;🎒 Antes de empezar&quot;">​</a></h2><ul><li>Tener instalado y configurado el plugin OpenCode Agent Skills</li><li>Conocer los conceptos básicos de skills (se recomienda leer primero <a href="./../../start/what-is-opencode-agent-skills/">¿Qué es OpenCode Agent Skills?</a>)</li><li>(Opcional) Tener plugins o skills de Claude Code instalados</li></ul><h2 id="paso-a-paso" tabindex="-1">Paso a paso <a class="header-anchor" href="#paso-a-paso" aria-label="Permalink to &quot;Paso a paso&quot;">​</a></h2><h3 id="paso-1-verificar-que-los-skills-de-claude-sean-descubiertos" tabindex="-1">Paso 1: Verificar que los skills de Claude sean descubiertos <a class="header-anchor" href="#paso-1-verificar-que-los-skills-de-claude-sean-descubiertos" aria-label="Permalink to &quot;Paso 1: Verificar que los skills de Claude sean descubiertos&quot;">​</a></h3><p><strong>Por qué</strong> Confirmar que el plugin puede escanear correctamente tus directorios de skills de Claude Code.</p><p>Llama a la herramienta en OpenCode:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>get_available_skills()</span></span></code></pre></div><p><strong>Deberías ver</strong>: La lista de skills devuelta incluye skills de <code>.claude/skills/</code>, <code>~/.claude/skills/</code>, <code>~/.claude/plugins/</code>, y el campo <code>source</code> de cada skill muestra su origen (como <code>claude-project</code>, <code>claude-user</code>, <code>claude-plugins</code>).</p><p><strong>Punto de verificación ✅</strong>: Confirma que la lista incluye los skills de Claude esperados.</p><h3 id="paso-2-cargar-un-skill-de-claude" tabindex="-1">Paso 2: Cargar un skill de Claude <a class="header-anchor" href="#paso-2-cargar-un-skill-de-claude" aria-label="Permalink to &quot;Paso 2: Cargar un skill de Claude&quot;">​</a></h3><p><strong>Por qué</strong> Verificar que el mecanismo de mapeo de herramientas funciona correctamente.</p><p>Llama a la herramienta para cargar un skill de Claude:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>use_skill(skill=&quot;nombre-de-tu-skill&quot;)</span></span></code></pre></div><p><strong>Deberías ver</strong>: Un mensaje de éxito, como <code>Skill &quot;xxx&quot; loaded.</code>.</p><p><strong>Punto de verificación ✅</strong>: La IA ahora puede usar las instrucciones de ese skill.</p><h3 id="paso-3-verificar-que-el-mapeo-de-herramientas-funciona" tabindex="-1">Paso 3: Verificar que el mapeo de herramientas funciona <a class="header-anchor" href="#paso-3-verificar-que-el-mapeo-de-herramientas-funciona" aria-label="Permalink to &quot;Paso 3: Verificar que el mapeo de herramientas funciona&quot;">​</a></h3><p><strong>Por qué</strong> Confirmar que la IA puede llamar correctamente a las herramientas de OpenCode en lugar de las de Claude.</p><p>Pide a la IA una tarea que requiera las herramientas del skill, por ejemplo:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Por favor, usa la función todo del skill para crear una lista de tareas.</span></span></code></pre></div><p><strong>Deberías ver</strong>: La IA llama correctamente a la herramienta <code>todowrite</code> de OpenCode, no a la herramienta <code>TodoWrite</code> de Claude.</p><div class="tip custom-block"><p class="custom-block-title">¿Cómo verificar que el mapeo funciona?</p><p>Revisa el registro de llamadas a herramientas de la IA (si tienes el modo de depuración activado), verás que llama a <code>todowrite</code> en lugar de <code>TodoWrite</code>.</p></div><p><strong>Punto de verificación ✅</strong>: La llamada a la herramienta tiene éxito y la tarea se completa.</p><h2 id="errores-comunes" tabindex="-1">Errores comunes <a class="header-anchor" href="#errores-comunes" aria-label="Permalink to &quot;Errores comunes&quot;">​</a></h2><h3 id="_1-formato-de-plugin-incompatible" tabindex="-1">1. Formato de plugin incompatible <a class="header-anchor" href="#_1-formato-de-plugin-incompatible" aria-label="Permalink to &quot;1. Formato de plugin incompatible&quot;">​</a></h3><p><strong>Problema</strong>: Los plugins antiguos de Claude usan el formato v1, los nuevos usan v2, lo que hace que algunos skills no sean descubiertos.</p><p><strong>Causa</strong>: Las estructuras de <code>installed_plugins.json</code> de v1 y v2 son diferentes.</p><p><strong>Solución</strong>: El plugin soporta ambos formatos, no se necesita conversión manual. Si aún no se descubren los skills, verifica que <code>~/.claude/plugins/installed_plugins.json</code> exista y tenga el formato correcto.</p><h3 id="_2-el-mapeo-de-herramientas-no-funciona" tabindex="-1">2. El mapeo de herramientas no funciona <a class="header-anchor" href="#_2-el-mapeo-de-herramientas-no-funciona" aria-label="Permalink to &quot;2. El mapeo de herramientas no funciona&quot;">​</a></h3><p><strong>Problema</strong>: La IA sigue llamando a los nombres de herramientas de Claude, causando errores.</p><p><strong>Causa</strong>: El contenido del skill puede estar evitando la guía de mapeo de herramientas, o está usando llamadas a herramientas codificadas directamente.</p><p><strong>Solución</strong>:</p><ul><li>Confirma que el skill se carga antes de usarse, en lugar de llamar directamente a las herramientas</li><li>Si el skill tiene ejemplos de código, cambia manualmente los nombres de herramientas al formato de OpenCode</li></ul><h3 id="_3-conflicto-de-nombres-de-skills" tabindex="-1">3. Conflicto de nombres de skills <a class="header-anchor" href="#_3-conflicto-de-nombres-de-skills" aria-label="Permalink to &quot;3. Conflicto de nombres de skills&quot;">​</a></h3><p><strong>Problema</strong>: Skills con el mismo nombre en diferentes ubicaciones, se carga la versión incorrecta.</p><p><strong>Causa</strong>: Sobrescritura debido a la prioridad de descubrimiento de skills.</p><p><strong>Solución</strong>:</p><ul><li>Verifica el campo <code>source</code> del skill para confirmar su origen</li><li>Usa el formato de namespace para especificar explícitamente el origen: <code>use_skill(skill=&quot;user:nombre-skill&quot;)</code> o <code>use_skill(skill=&quot;claude-plugins:nombre-skill&quot;)</code></li></ul><details class="details custom-block"><summary>Sintaxis de namespace</summary><p>El plugin soporta el formato <code>namespace:nombre-skill</code>:</p><ul><li><code>project:nombre-skill</code> - Skill de OpenCode a nivel de proyecto</li><li><code>claude-project:nombre-skill</code> - Skill de Claude a nivel de proyecto</li><li><code>user:nombre-skill</code> - Skill de OpenCode a nivel de usuario</li><li><code>claude-user:nombre-skill</code> - Skill de Claude a nivel de usuario</li><li><code>claude-plugins:nombre-skill</code> - Skill del marketplace de plugins de Claude</li></ul></details><h2 id="resumen-de-la-leccion" tabindex="-1">Resumen de la lección <a class="header-anchor" href="#resumen-de-la-leccion" aria-label="Permalink to &quot;Resumen de la lección&quot;">​</a></h2><p>El plugin OpenCode Agent Skills te permite reutilizar skills de Claude Code sin problemas mediante un mecanismo de compatibilidad de tres capas:</p><ul><li><strong>Descubrimiento automático</strong> - Escanea skills desde 6 ubicaciones, cubriendo nivel de proyecto, usuario y plugins</li><li><strong>Mapeo de herramientas</strong> - Convierte automáticamente los nombres de herramientas de Claude a nombres de OpenCode</li><li><strong>Soporte de formatos</strong> - Compatible con los formatos v1 y v2 de plugins de Claude</li></ul><p>No necesitas reescribir skills, simplemente instálalos y úsalos, el plugin manejará automáticamente los problemas de compatibilidad.</p><h2 id="proxima-leccion" tabindex="-1">Próxima lección <a class="header-anchor" href="#proxima-leccion" aria-label="Permalink to &quot;Próxima lección&quot;">​</a></h2><blockquote><p>En la próxima lección aprenderemos sobre <strong><a href="./../superpowers-integration/">Integración con flujos de trabajo Superpowers</a></strong>.</p><p>Aprenderás:</p><ul><li>Cómo habilitar el modo Superpowers</li><li>Detección y carga automática de skills Superpowers</li><li>Cómo los flujos de trabajo estrictos mejoran la eficiencia del desarrollo</li></ul></blockquote><hr><h2 id="apendice-referencia-del-codigo-fuente" tabindex="-1">Apéndice: Referencia del código fuente <a class="header-anchor" href="#apendice-referencia-del-codigo-fuente" aria-label="Permalink to &quot;Apéndice: Referencia del código fuente&quot;">​</a></h2><details><summary><strong>Haz clic para ver las ubicaciones del código fuente</strong></summary><blockquote><p>Fecha de actualización: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Funcionalidad</th><th>Ruta del archivo</th><th>Líneas</th></tr></thead><tbody><tr><td>Definición del mapeo de herramientas</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/claude.ts#L19-L25" target="_blank" rel="noreferrer"><code>src/claude.ts</code></a></td><td>19-25</td></tr><tr><td>Definición de tipos de formato v1/v2</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/claude.ts#L35-L61" target="_blank" rel="noreferrer"><code>src/claude.ts</code></a></td><td>35-61</td></tr><tr><td>Extracción de rutas de instalación de plugins</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/claude.ts#L68-L77" target="_blank" rel="noreferrer"><code>src/claude.ts</code></a></td><td>68-77</td></tr><tr><td>Descubrimiento de skills de plugins</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/claude.ts#L82-L105" target="_blank" rel="noreferrer"><code>src/claude.ts</code></a></td><td>82-105</td></tr><tr><td>Descubrimiento de skills del marketplace</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/claude.ts#L115-L180" target="_blank" rel="noreferrer"><code>src/claude.ts</code></a></td><td>115-180</td></tr><tr><td>Descubrimiento de skills en caché</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/claude.ts#L193-L253" target="_blank" rel="noreferrer"><code>src/claude.ts</code></a></td><td>193-253</td></tr><tr><td>Lista de prioridad de descubrimiento de skills</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/skills.ts#L241-L254" target="_blank" rel="noreferrer"><code>src/skills.ts</code></a></td><td>241-254</td></tr><tr><td>Lógica de deduplicación de skills con mismo nombre</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/skills.ts#L256-L260" target="_blank" rel="noreferrer"><code>src/skills.ts</code></a></td><td>256-260</td></tr><tr><td>Importación de toolTranslation</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/tools.ts#L15" target="_blank" rel="noreferrer"><code>src/tools.ts</code></a></td><td>15</td></tr><tr><td>Inyección del mapeo de herramientas</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/tools.ts#L238-L249" target="_blank" rel="noreferrer"><code>src/tools.ts</code></a></td><td>238-249</td></tr></tbody></table><p><strong>Constantes clave</strong>:</p><ul><li><code>toolTranslation</code>: Cadena XML de la guía de mapeo de herramientas, inyectada en el contexto de la sesión al cargar un skill. Definida en <code>src/claude.ts:19-25</code>, importada en <code>src/tools.ts:15</code></li></ul><p><strong>Funciones clave</strong>:</p><ul><li><code>getPluginInstallPaths()</code>: Extrae las rutas de instalación de plugins desde los formatos v1/v2</li><li><code>discoverSkillsFromPluginDir()</code>: Escanea el subdirectorio skills/ del directorio de plugins</li><li><code>discoverMarketplaceSkills()</code>: Descubre skills desde <code>~/.claude/plugins/marketplaces/</code> (prioritario)</li><li><code>discoverPluginCacheSkills()</code>: Descubre skills desde <code>~/.claude/plugins/cache/</code> (como alternativa)</li><li><code>findFile()</code>: Busca recursivamente un nombre de archivo específico (función utilitaria)</li></ul><p><strong>Flujo importante</strong>:</p><ol><li>Al inicializar el plugin se llama a <code>discoverAllSkills()</code> → recorre las 6 rutas de descubrimiento</li><li>Al descubrir skills de plugins de Claude se llama a <code>discoverMarketplaceSkills()</code> o <code>discoverPluginCacheSkills()</code></li><li>Al cargar un skill, la herramienta <code>use_skill</code> inserta <code>toolTranslation</code> en el contenido XML (línea 244)</li></ol></details>`,68)])])}const h=a(o,[["render",d]]);export{m as __pageData,h as default};
